#include <string.h>

int process_username(const char *username) {
    char buffer[16];

    strcpy(buffer, username);

    printf("Username: %s\n", buffer);
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int process_username(const char *username) {
    char buffer[16];

    if (strlen(username) > 16) {
        return -1;
    }

    for (int i = 0; i < strlen(username); i++) {
        if (!isalnum(username[i])) {
            return -1;
        }
    }

    strncpy(buffer, username, 16);

    printf("Username: %s\n", buffer);
    return 0;
}

